using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Columns;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using TextAnalysis;

var config = DefaultConfig.Instance
    .AddJob(Job.ShortRun.WithId("net9.0").DontEnforcePowerPlan())
    .AddJob(Job.ShortRun.WithId("net10.0").DontEnforcePowerPlan())
    .HideColumns(Column.EnvironmentVariables, Column.RatioSD, Column.AllocRatio);

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config);

[MemoryDiagnoser(false)]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // Generate a representative text with ~1000 words
        var words = new string[]
        {
            "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
            "performance", "benchmarking", "analysis", "algorithm", "structure",
            "optimization", "measurement", "comparison", "evaluation", "testing",
            "implementation", "development", "engineering", "architecture",
            "a", "is", "of", "to", "in", "it", "on", "at"
        };
        var rng = new Random(42);
        var sb = new System.Text.StringBuilder();
        for (int i = 0; i < 1000; i++)
        {
            if (i > 0) sb.Append(' ');
            sb.Append(words[rng.Next(words.Length)]);
        }
        _analyzer = new TextAnalyzer(sb.ToString());
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}
EOF

